async (params, browser) => {
  // Open page
  await browser.open(`${params.list_url}`)

  // Wait for content
  await browser.waitForSelector('ul.poster-list, ul.film-list, .poster-container', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const listTitle = document.querySelector('h1')?.textContent?.trim()||document.querySelector('meta[property="og:title"]')?.getAttribute('content')||''; const desc = document.querySelector('div.body-text p')?.textContent?.trim()?.substring(0,500)||document.querySelector('meta[property="og:description"]')?.getAttribute('content')||''; const owner = document.querySelector('span[itemprop="name"], a.name')?.textContent?.trim()||''; const films = Array.from(document.querySelectorAll('li.poster-container')).slice(0,50).map((el,i) => { const img = el.querySelector('img'); const link = el.querySelector('div.film-poster'); const slug = link?link.getAttribute('data-film-slug'):''; return { rank: i+1, title: img?img.getAttribute('alt'):'', url: slug?'https://letterboxd.com/film/'+slug+'/':'' }; }).filter(f=>f.title); return { list_title: listTitle, owner, description: desc, films, url: window.location.href }`)

  return page_data
}
